/**
 * ========================================================================
 * EXTENSION: Advanced Predictive Analytics
 * Trend Detection, Forecasting, and Correlation Discovery
 * ========================================================================
 */

/**
 * Historical data point for trend analysis
 */
export interface TrendPoint {
  timestamp: number;
  btcPrice: number;
  ethPrice: number;
  sp500: number;
  vix: number;
  volatility: number;
}

/**
 * Trend analysis result
 */
export interface TrendAnalysis {
  direction: 'up' | 'down' | 'sideways';
  strength: number; // 0-1
  momentum: number; // Rate of change
  duration: number; // Sessions this trend has persisted
  confidence: number;
}

/**
 * Forecast for future values
 */
export interface Forecast {
  timeHorizon: '1h' | '4h' | '24h';
  btcPrediction: { direction: 'up' | 'down' | 'stable'; magnitude: number; confidence: number };
  ethPrediction: { direction: 'up' | 'down' | 'stable'; magnitude: number; confidence: number };
  volatilityPrediction: VolatilityLevel;
  recommendedAction: string;
}

/**
 * Correlation between assets
 */
export interface AssetCorrelation {
  pair: string;
  coefficient: number; // -1 to 1
  strength: 'weak' | 'moderate' | 'strong' | 'inverse';
  significance: number; // 0-1
}

/**
 * Session timing recommendation with context
 */
export interface SessionTimingRecommendation {
  mode: SessionMode;
  duration: number; // Recommended session length in minutes
  priority: string[];
  opportunities: string[];
  risks: string[];
  checkBackIn: number; // Minutes until re-evaluation
  rationale: string;
}

/**
 * Trend Analyzer - Detect momentum over multiple snapshots
 */
export class TrendAnalyzer {
  private history: TrendPoint[] = [];
  private maxHistory: number = 20; // Keep last 20 data points

  /**
   * Add a new snapshot to history
   */
  addSnapshot(snapshot: EconomicSnapshot): void {
    const point: TrendPoint = {
      timestamp: new Date(snapshot.capturedAt).getTime(),
      btcPrice: snapshot.crypto?.bitcoin.price ?? 0,
      ethPrice: snapshot.crypto?.ethereum.price ?? 0,
      sp500: snapshot.indices?.sp500 ?? 0,
      vix: snapshot.indices?.vix ?? 0,
      volatility: (snapshot.crypto?.bitcoin.change24h ?? 0) + 
                 (snapshot.crypto?.ethereum.change24h ?? 0)
    };

    this.history.push(point);

    // Maintain window size
    if (this.history.length > this.maxHistory) {
      this.history.shift();
    }
  }

  /**
   * Analyze trend direction and strength
   */
  analyzeTrend(asset: 'btc' | 'eth' | 'vix'): TrendAnalysis {
    if (this.history.length < 3) {
      return {
        direction: 'sideways',
        strength: 0,
        momentum: 0,
        duration: 0,
        confidence: 0.5
      };
    }

    const prices = this.history.map(p => 
      asset === 'btc' ? p.btcPrice : 
      asset === 'eth' ? p.ethPrice : 
      p.vix
    );

    // Calculate momentum (slope of recent prices)
    const recent = prices.slice(-5);
    const momentum = this.calculateSlope(recent);

    // Determine direction
    const avgChange = momentum;
    let direction: 'up' | 'down' | 'sideways';
    if (avgChange > 0.001) direction = 'up';
    else if (avgChange < -0.001) direction = 'down';
    else direction = 'sideways';

    // Calculate strength based on consistency
    const variance = this.calculateVariance(prices);
    const strength = Math.min(1, 1 / (1 + variance * 100));

    // Find trend duration
    let duration = 0;
    for (let i = this.history.length - 1; i > 0; i--) {
      const thisDir = this.getDirection(prices[i], prices[i-1]);
      if (thisDir === direction) duration++;
      else break;
    }

    return {
      direction,
      strength,
      momentum,
      duration,
      confidence: Math.min(1, (this.history.length / 10) * strength)
    };
  }

  /**
   * Check for trend reversals
   */
  detectReversal(asset: 'btc' | 'eth'): { detected: boolean; strength: number } {
    if (this.history.length < 6) return { detected: false, strength: 0 };

    const prices = this.history.map(p => 
      asset === 'btc' ? p.btcPrice : p.ethPrice
    );

    const prev = prices.slice(-6, -3);
    const recent = prices.slice(-3);

    const prevDirection = this.getDirection(prev[prev.length-1], prev[0]);
    const recentDirection = this.getDirection(recent[recent.length-1], recent[0]);

    if (prevDirection !== 'sideways' && prevDirection !== recentDirection) {
      return { 
        detected: true, 
        strength: Math.abs(recent[recent.length-1] - recent[0]) / recent[0] * 100 
      };
    }

    return { detected: false, strength: 0 };
  }

  private calculateSlope(values: number[]): number {
    const n = values.length;
    if (n < 2) return 0;

    const sumX = values.reduce((a, b, i) => a + i, 0);
    const sumY = values.reduce((a, b) => a + b, 0);
    const sumXY = values.reduce((a, b, i) => a + i * b, 0);
    const sumXX = values.reduce((a, b, i) => a + i * i, 0);

    return (n * sumXY - sumX * sumY) / (n * sumXX - sumX * sumX);
  }

  private calculateVariance(values: number[]): number {
    const mean = values.reduce((a, b) => a + b, 0) / values.length;
    const squaredDiffs = values.map(v => Math.pow(v - mean, 2));
    return squaredDiffs.reduce((a, b) => a + b, 0) / values.length;
  }

  private getDirection(current: number, previous: number): 'up' | 'down' | 'sideways' {
    const change = (current - previous) / previous;
    if (change > 0.0005) return 'up';
    if (change < -0.0005) return 'down';
    return 'sideways';
  }

  getHistory(): TrendPoint[] {
    return [...this.history];
  }
}

/**
 * Forecast Engine - Predict future movements
 */
export class ForecastEngine {
  private trendAnalyzer: TrendAnalyzer;

  constructor(trendAnalyzer: TrendAnalyzer) {
    this.trendAnalyzer = trendAnalyzer;
  }

  /**
   * Generate forecast for next time horizon
   */
  forecast(horizon: '1h' | '4h' | '24h' = '1h'): Forecast {
    const btcTrend = this.trendAnalyzer.analyzeTrend('btc');
    const ethTrend = this.trendAnalyzer.analyzeTrend('eth');
    const vixTrend = this.trendAnalyzer.analyzeTrend('vix');

    // Weight: recent trend = 0.6, momentum = 0.4
    const btcPrediction = this.calculatePrediction(btcTrend);
    const ethPrediction = this.calculatePrediction(ethTrend);

    // Predict volatility based on VIX trend
    let volatilityPrediction: VolatilityLevel = 'stable';
    if (vixTrend.direction === 'up' && vixTrend.strength > 0.6) {
      volatilityPrediction = 'high';
    } else if (vixTrend.direction === 'up' && vixTrend.strength > 0.3) {
      volatilityPrediction = 'moderate';
    }

    return {
      timeHorizon: horizon,
      btcPrediction,
      ethPrediction,
      volatilityPrediction,
      recommendedAction: this.generateAction(btcPrediction, ethPrediction, volatilityPrediction)
    };
  }

  private calculatePrediction(trend: TrendAnalysis): 
    { direction: 'up' | 'down' | 'stable'; magnitude: number; confidence: number } {

    if (trend.confidence < 0.3) {
      return { direction: 'stable', magnitude: 0, confidence: trend.confidence };
    }

    const direction = trend.momentum > 0.001 ? 'up' : 
                      trend.momentum < -0.001 ? 'down' : 'stable';

    const magnitude = Math.min(5, Math.abs(trend.momentum * 100) * trend.strength);

    return {
      direction,
      magnitude,
      confidence: trend.confidence * trend.strength
    };
  }

  private generateAction(btc: Forecast['btcPrediction'], eth: Forecast['ethPrediction'], vol: VolatilityLevel): string {
    if (vol === 'high') {
      return 'DEFENSIVE: High volatility expected. Prioritize archival work only.';
    }
    if (btc.direction === eth.direction && btc.direction !== 'stable') {
      const dir = btc.direction;
      const confidence = Math.min(btc.confidence, eth.confidence);
      if (confidence > 0.6) {
        return `FLOW PROBABLE: Strong ${dir}ward momentum in both assets. Optimal for extension work.`;
      }
    }
    if (vol === 'moderate') {
      return 'CAUTIOUS: Mixed signals. Focus on testing and maintenance.';
    }
    return 'FLOW: Stable conditions. Creative work recommended.';
  }
}

/**
 * Correlation Analyzer - Find patterns between assets
 */
export class CorrelationAnalyzer {
  private trendAnalyzer: TrendAnalyzer;

  constructor(trendAnalyzer: TrendAnalyzer) {
    this.trendAnalyzer = trendAnalyzer;
  }

  /**
   * Calculate correlation between two assets
   */
  calculateCorrelation(asset1: 'btc' | 'eth' | 'sp500', asset2: 'btc' | 'eth' | 'sp500'): AssetCorrelation {
    const history = this.trendAnalyzer.getHistory();
    if (history.length < 5) {
      return { pair: `${asset1}-${asset2}`, coefficient: 0, strength: 'weak', significance: 0 };
    }

    const getValue = (p: TrendPoint, asset: string): number => {
      if (asset === 'btc') return p.btcPrice;
      if (asset === 'eth') return p.ethPrice;
      return p.sp500;
    };

    const values1 = history.map(p => getValue(p, asset1));
    const values2 = history.map(p => getValue(p, asset2));

    const coefficient = this.pearsonCorrelation(values1, values2);

    let strength: AssetCorrelation['strength'];
    const abs = Math.abs(coefficient);
    if (abs > 0.7) strength = 'strong';
    else if (abs > 0.4) strength = 'moderate';
    else if (abs > 0.2) strength = 'weak';
    else strength = 'weak';
    if (coefficient < -0.3) strength = 'inverse';

    return {
      pair: `${asset1}-${asset2}`,
      coefficient,
      strength,
      significance: Math.min(1, history.length / 20)
    };
  }

  /**
   * Find all significant correlations
   */
  findAllCorrelations(): AssetCorrelation[] {
    const pairs: [string, string][] = [
      ['btc', 'eth'],
      ['btc', 'sp500'],
      ['eth', 'sp500']
    ];

    return pairs.map(([a, b]) => 
      this.calculateCorrelation(a as 'btc' | 'eth' | 'sp500', b as 'btc' | 'eth' | 'sp500')
    ).filter(c => Math.abs(c.coefficient) > 0.2);
  }

  private pearsonCorrelation(x: number[], y: number[]): number {
    const n = Math.min(x.length, y.length);
    if (n === 0) return 0;

    const sumX = x.reduce((a, b) => a + b, 0);
    const sumY = y.reduce((a, b) => a + b, 0);
    const sumXY = x.slice(0, n).reduce((a, b, i) => a + b * y[i], 0);
    const sumX2 = x.reduce((a, b) => a + b * b, 0);
    const sumY2 = y.reduce((a, b) => a + b * b, 0);

    const numerator = n * sumXY - sumX * sumY;
    const denominator = Math.sqrt((n * sumX2 - sumX * sumX) * (n * sumY2 - sumY * sumY));

    return denominator === 0 ? 0 : numerator / denominator;
  }
}

/**
 * Session Planner - Generate sophisticated session recommendations
 */
export class SessionPlanner {
  private trendAnalyzer: TrendAnalyzer;
  private forecastEngine: ForecastEngine;
  private correlationAnalyzer: CorrelationAnalyzer;

  constructor() {
    this.trendAnalyzer = new TrendAnalyzer();
    this.forecastEngine = new ForecastEngine(this.trendAnalyzer);
    this.correlationAnalyzer = new CorrelationAnalyzer(this.trendAnalyzer);
  }

  getTrendAnalyzer(): TrendAnalyzer { return this.trendAnalyzer; }
  getForecastEngine(): ForecastEngine { return this.forecastEngine; }
  getCorrelationAnalyzer(): CorrelationAnalyzer { return this.correlationAnalyzer; }

  /**
   * Generate comprehensive session timing recommendation
   */
  planSession(currentSnapshot: EconomicSnapshot): SessionTimingRecommendation {
    // Update history
    this.trendAnalyzer.addSnapshot(currentSnapshot);

    // Get all analyses
    const timing = analyzeTiming(currentSnapshot);
    const forecast = this.forecastEngine.forecast('1h');
    const correlations = this.correlationAnalyzer.findAllCorrelations();
    const btcTrend = this.trendAnalyzer.analyzeTrend('btc');
    const reversal = this.trendAnalyzer.detectReversal('btc');

    // Calculate recommended duration based on conditions
    let duration = 60; // default 60 minutes
    let checkBackIn = 30;

    if (timing.mode === 'flow') {
      duration = 90;
      checkBackIn = 60;
    } else if (timing.mode === 'defensive') {
      duration = 30;
      checkBackIn = 15;
    }

    // Build opportunities and risks
    const opportunities: string[] = [];
    const risks: string[] = [];

    if (btcTrend.direction === 'up' && btcTrend.strength > 0.6) {
      opportunities.push('Strong upward momentum detected--optimal for extension work');
    }
    if (reversal.detected) {
      risks.push(`Reversal detected (${reversal.strength.toFixed(2)}%)--conditions may shift`);
    }
    if (forecast.volatilityPrediction === 'high') {
      risks.push('High volatility forecasted--consider shorter sessions');
    }
    if (correlations.some(c => c.strength === 'strong')) {
      const strong = correlations.find(c => c.strength === 'strong');
      if (strong) {
        opportunities.push(`Strong ${strong.pair} correlation (${strong.coefficient.toFixed(2)})--patterns predictable`);
      }
    }

    // Generate rationale
    let rationale = `Current mode: ${timing.mode}`;
    if (btcTrend.duration > 2) {
      rationale += ` | BTC ${btcTrend.direction}ward trend for ${btcTrend.duration} snapshots`;
    }
    if (forecast.btcPrediction.confidence > 0.5) {
      rationale += ` | Forecast: ${forecast.btcPrediction.direction} (${(forecast.btcPrediction.confidence * 100).toFixed(0)}% confidence)`;
    }

    return {
      mode: timing.mode,
      duration,
      priority: MODE_DESCRIPTIONS[timing.mode].permitted.slice(0, 2),
      opportunities: opportunities.length > 0 ? opportunities : ['Stable environment conducive to focus'],
      risks: risks.length > 0 ? risks : ['No significant risks detected'],
      checkBackIn,
      rationale
    };
  }

  /**
   * Format full predictive report
   */
  formatFullReport(recommendation: SessionTimingRecommendation, currentSnapshot: EconomicSnapshot): string {
    const lines = [
      '╔' + '═'.repeat(58) + '╗',
      '║' + ' '.repeat(15) + 'NEXUS PREDICTIVE ANALYTICS' + ' '.repeat(16) + '║',
      '╠' + '═'.repeat(58) + '╣',
      '',
      '📊 SESSION TIMING RECOMMENDATION',
      '',
      `   Mode:        ${MODE_DESCRIPTIONS[recommendation.mode].label}`,
      `   Duration:    ${recommendation.duration} minutes`,
      `   Check Back:  Every ${recommendation.checkBackIn} minutes`,
      '',
      '🎯 PRIORITY FOCUS',
      ...recommendation.priority.map(p => `   • ${p}`),
      '',
      '💡 OPPORTUNITIES',
      ...recommendation.opportunities.map(o => `   • ${o}`),
      '',
      '⚠️  RISKS',
      ...recommendation.risks.map(r => `   • ${r}`),
      '',
      '🧮 RATIONALE',
      `   ${recommendation.rationale}`,
      '',
      '────────────────────────────────────────',
    ];

    // Add correlations if any
    const correlations = this.correlationAnalyzer.findAllCorrelations();
    if (correlations.length > 0) {
      lines.push('', '🔗 CORRELATIONS');
      correlations.forEach(c => {
        const symbol = c.coefficient > 0 ? '↗️' : '↘️';
        lines.push(`   ${symbol} ${c.pair}: ${c.strength} (${c.coefficient.toFixed(3)})`);
      });
    }

    lines.push('', '╚' + '═'.repeat(58) + '╝');

    return lines.join('\n');
  }
}

/**
 * Extended Predictive Analytics export
