 * Extended Predictive Analytics Tests
 * ========================================================================
 */

import { 
  TrendAnalyzer, 
  ForecastEngine, 
  CorrelationAnalyzer, 
  SessionPlanner 
} from './predictive';
import type { EconomicSnapshot } from './types';

describe('TrendAnalyzer', () => {
  let analyzer: TrendAnalyzer;

  beforeEach(() => {
    analyzer = new TrendAnalyzer();
  });

  const createSnapshot = (partial: Partial<EconomicSnapshot> = {}): EconomicSnapshot => ({
    id: 'test',
    sessionId: 'test-session',
    capturedAt: new Date().toISOString(),
    crypto: {
      bitcoin: { price: 65000, change24h: 0.5, volume24h: 1000000, dominance: 0.45 },
      ethereum: { price: 3500, change24h: 0.3, volume24h: 500000, gasPrice: 20 },
      other: []
    },
    indices: {
      sp500: 4500,
      nasdaq: 14000,
      vix: 20
    },
    ...partial
  });

  test('should initialize with empty history', () => {
    const trend = analyzer.analyzeTrend('btc');
    expect(trend.direction).toBe('sideways');
    expect(trend.strength).toBe(0);
    expect(trend.confidence).toBe(0.5);
  });

  test('should detect upward trend', () => {
    // Add snapshots showing upward momentum
    for (let i = 0; i < 5; i++) {
      analyzer.addSnapshot(createSnapshot({
        crypto: {
          bitcoin: { price: 60000 + i * 1000, change24h: 0.5 + i * 0.1 },
          ethereum: { price: 3500, change24h: 0.3, volume24h: 500000, gasPrice: 20 },
          other: []
        },
        indices: { sp500: 4500, nasdaq: 14000, vix: 20 }
      }));
    }

    const trend = analyzer.analyzeTrend('btc');
    expect(trend.direction).toBe('up');
    expect(trend.strength).toBeGreaterThan(0);
    expect(trend.momentum).toBeGreaterThan(0);
  });

  test('should detect downward trend', () => {
    for (let i = 0; i < 5; i++) {
      analyzer.addSnapshot(createSnapshot({
        crypto: {
          bitcoin: { price: 65000 - i * 1000, change24h: -0.5 - i * 0.1 },
          ethereum: { price: 3500, change24h: 0.3, volume24h: 500000, gasPrice: 20 },
          other: []
        },
        indices: { sp500: 4500, nasdaq: 14000, vix: 20 }
      }));
    }

    const trend = analyzer.analyzeTrend('btc');
    expect(trend.direction).toBe('down');
    expect(trend.momentum).toBeLessThan(0);
  });

  test('should maintain max history size', () => {
