/**
 * Situation-Aware Goal System
 * Nexus Integration Layer
 * 
 * Connects predictive analytics to goal management.
 * Goals can be deferred/reactivated based on external conditions.
 */

import { SessionPlanner } from './predictive';
import { GoalManager, type Goal, type GoalPriority } from '../core/goals';
import type { EconomicSnapshot } from './types';

/**
 * Goal situational parameters
 */
export interface GoalSituation {
  goalId: string;
  // When to defer
  deferWhen: {
    volatilityAbove?: number;       // Combined BTC+ETH%
    mode?: ('flow' | 'cautious' | 'defensive')[];
    vixAbove?: number;
  };
  // When to reactivate
  activateWhen: {
    volatilityBelow?: number;
    mode?: ('flow' | 'cautious')[];
    vixBelow?: number;
  };
  // Priority adjustment
  priorityModifiers: {
    highVolatility: GoalPriority;
    lowVolatility: GoalPriority;
  };
}

/**
 * Situation Engine
 * Manages goals based on external conditions
 */
export class SituationEngine {
  private planner: SessionPlanner;
  private goals: GoalManager;
  private situationMap: Map<string, GoalSituation> = new Map();

  constructor() {
    this.planner = new SessionPlanner();
    this.goals = new GoalManager();
  }

  /**
   * Register a goal with situational parameters
   */
  async registerGoalSituation(
    goalId: string,
    situation: Omit<GoalSituation, 'goalId'>
  ): Promise<void> {
    await this.goals.initialize();
    const goal = await this.goals.getGoal(goalId);
    if (!goal) {
      throw new Error(`Goal ${goalId} not found`);
    }

    this.situationMap.set(goalId, { goalId, ...situation });
  }

  /**
   * Evaluate all goals against current situation
   */
  async evaluateSituation(snapshot: EconomicSnapshot): Promise<{
    deferred: string[];
    activated: string[];
    adjusted: string[];
  }> {
    const recommendation = this.planner.planSession(snapshot);
    const volatility = (snapshot.crypto?.bitcoin.change24h ?? 0) + 
                      (snapshot.crypto?.ethereum.change24h ?? 0);
    const vix = snapshot.indices?.vix.value ?? 20;

    const deferred: string[] = [];
    const activated: string[] = [];
    const adjusted: string[] = [];

    for (const [goalId, situation] of this.situationMap) {
      const goal = await this.goals.getGoal(goalId);
      if (!goal) continue;

      // Check deferral conditions
      if (goal.status === 'active') {
        let shouldDefer = false;

        if (situation.deferWhen.volatilityAbove && 
            Math.abs(volatility) > situation.deferWhen.volatilityAbove) {
          shouldDefer = true;
        }

        if (situation.deferWhen.mode?.includes(recommendation.mode)) {
          shouldDefer = true;
        }

        if (situation.deferWhen.vixAbove && vix > situation.deferWhen.vixAbove) {
          shouldDefer = true;
        }

        if (shouldDefer) {
          await this.goals.deferGoal(
            goalId,
            `Deferred: ${recommendation.mode} mode detected (volatility: ${volatility.toFixed(2)}%, VIX: ${vix})`
          );
          deferred.push(goalId);
        }
      }

      // Check reactivation conditions
      if (goal.status === 'deferred') {
        let shouldActivate = true;

        if (situation.activateWhen.volatilityBelow && 
            Math.abs(volatility) > situation.activateWhen.volatilityBelow) {
          shouldActivate = false;
        }

        if (situation.activateWhen.mode && 
            !situation.activateWhen.mode.includes(recommendation.mode)) {
          shouldActivate = false;
        }

        if (situation.activateWhen.vixBelow && vix > situation.activateWhen.vixBelow) {
          shouldActivate = false;
        }

        if (shouldActivate) {
          await this.goals.reactivateGoal(goalId);
          activated.push(goalId);
        }
      }
    }

    return { deferred, activated, adjusted };
  }

  /**
   * Get situation report
   */
  async getSituationReport(snapshot: EconomicSnapshot): Promise<string> {
    const recomendation = this.planner.planSession(snapshot);
    const result = await this.evaluateSituation(snapshot);

    const lines = [
      '╔' + '═'.repeat(60) + '╗',
      '║' + ' '.repeat(15) + 'SITUATION-AWARE GOAL REPORT' + ' '.repeat(18) + '║',
      '╠' + '═'.repeat(60) + '╣',
      '',
      `Session Mode: ${recomendation.mode.toUpperCase()}`,
      `Monitored Goals: ${this.situationMap.size}`,
      '',
      'ACTIONS TAKEN:',
      `  Deferred:  ${result.deferred.length} goal(s)`,
      `  Activated: ${result.activated.length} goal(s)`,
      `  Adjusted:  ${result.adjusted.length} goal(s)`,
      '',
      '╚' + '═'.repeat(60) + '╝',
    ];

    return lines.join('\n');
  }
}

export default SituationEngine;
